const crypto = require('crypto');
const stripe = require('stripe')(process.env.STRIPE_SECRET_KEY);

// Generate RSA key pair for customer (do once during account setup)
function generateCustomerKeyPair() {
  const { publicKey, privateKey } = crypto.generateKeyPairSync('rsa', {
    modulusLength: 2048,
    publicKeyEncoding: { type: 'spki', format: 'pem' },
    privateKeyEncoding: { type: 'pkcs8', format: 'pem' }
  });

  // Store public key in database, private key in customer's secure enclave/device
  return { publicKey, privateKey };
}

// Customer signs transaction on client side (mobile app/browser)
function signTransactionClient(transactionData, customerPrivateKey) {
  const dataToSign = JSON.stringify({
    amount: transactionData.amount,
    currency: transactionData.currency,
    merchantId: transactionData.merchantId,
    timestamp: transactionData.timestamp,
    nonce: crypto.randomBytes(16).toString('hex')
  });

  const signature = crypto.sign(
    'sha256',
    Buffer.from(dataToSign),
    {
      key: customerPrivateKey,
      padding: crypto.constants.RSA_PKCS1_PSS_PADDING,
      saltLength: crypto.constants.RSA_PSS_SALTLEN_DIGEST
    }
  );

  return {
    data: dataToSign,
    signature: signature.toString('base64')
  };
}

// Server verifies signature before processing payment
async function processSignedPayment(signedTransaction, customerId) {
  try {
    // Retrieve customer's public key from database
    const customer = await db.customers.findById(customerId);
    const publicKey = customer.publicKey;

    // Verify signature
    const isValid = crypto.verify(
      'sha256',
      Buffer.from(signedTransaction.data),
      {
        key: publicKey,
        padding: crypto.constants.RSA_PKCS1_PSS_PADDING,
        saltLength: crypto.constants.RSA_PSS_SALTLEN_DIGEST
      },
      Buffer.from(signedTransaction.signature, 'base64')
    );

    if (!isValid) {
      throw new Error('Invalid transaction signature - authorization denied');
    }

    // Parse signed data and validate timestamp (prevent replay attacks)
    const txData = JSON.parse(signedTransaction.data);
    const txAge = Date.now() - txData.timestamp;
    if (txAge > 300000) { // 5 minutes
      throw new Error('Transaction signature expired');
    }

    // Process payment with Stripe
    const paymentIntent = await stripe.paymentIntents.create({
      amount: txData.amount,
      currency: txData.currency,
      customer: customerId,
      metadata: {
        signed_data: signedTransaction.data,
        signature: signedTransaction.signature,
        signature_algorithm: 'RSA-SHA256-PSS',
        public_key_fingerprint: crypto.createHash('sha256').update(publicKey).digest('hex')
      }
    });

    // Store signature in tamper-proof audit log
    await auditLog.create({
      event_type: 'payment_authorized',
      customer_id: customerId,
      payment_intent_id: paymentIntent.id,
      amount: txData.amount,
      signature: signedTransaction.signature,
      signed_data: signedTransaction.data,
      verification_status: 'valid',
      timestamp: new Date(),
      hash: crypto.createHash('sha256').update(JSON.stringify(paymentIntent)).digest('hex')
    });

    return { success: true, paymentIntent };

  } catch (error) {
    console.error('Payment signature verification failed:', error);
    throw error;
  }
}

